const queries = [
['q-senolytics','https://clinicaltrials.gov/api/v2/studies?query.term=senolytics&pageSize=100&countTotal=true'],
['q-dq-phrase','https://clinicaltrials.gov/api/v2/studies?query.term=%22D%2BQ%22&pageSize=100&countTotal=true'],
['q-dasatinib-quercetin','https://clinicaltrials.gov/api/v2/studies?query.term=dasatinib%20quercetin&pageSize=100&countTotal=true'],
['q-fisetin','https://clinicaltrials.gov/api/v2/studies?query.term=fisetin&pageSize=100&countTotal=true'],
['q-senolytic','https://clinicaltrials.gov/api/v2/studies?query.term=senolytic&pageSize=100&countTotal=true'],
['q-senescent-cell','https://clinicaltrials.gov/api/v2/studies?query.term=%22senescent%20cell%22&pageSize=100&countTotal=true'],
['q-targeting-cellular-senescence','https://clinicaltrials.gov/api/v2/studies?query.term=%22targeting%20cellular%20senescence%22&pageSize=100&countTotal=true']
];
const map = new Map();
for (const [qid,url] of queries) {
  const data = await (await fetch(url)).json();
  for (const s of data.studies ?? []) {
    const p=s.protocolSection; const id=p.identificationModule.nctId;
    const row=map.get(id)||{id,title:p.identificationModule.briefTitle,status:p.statusModule.overallStatus,queries:[]};
    row.queries.push(qid); map.set(id,row);
  }
}
const active = [...map.values()].filter(r => ['RECRUITING','ENROLLING_BY_INVITATION','ACTIVE_NOT_RECRUITING','NOT_YET_RECRUITING','SUSPENDED'].includes(r.status));
console.log(JSON.stringify({unique: map.size, activeCount: active.length, active: active.map(r=>({id:r.id,status:r.status,title:r.title,queries:r.queries}))}, null, 2));
